mapper.insert:
INSERT INTO ATTENDANCE_RECORDS (
    WORKPLACE_ID, USER_ID, WORK_DATE, CHECK_IN_AT, STATUS, NOTE, WORKED_MINUTES, BASE_WAGE, FINAL_WAGE
) VALUES (
    #{workplaceId}, #{userId}, #{workDate}, #{checkInAt}, #{status}, #{note}, #{workedMinutes}, #{baseWage}, #{finalWage}
)

mapper.select:
SELECT ID, WORKPLACE_ID, USER_ID, WORK_DATE, CHECK_IN_AT, CHECK_OUT_AT, STATUS,
       WORKED_MINUTES, BASE_WAGE, FINAL_WAGE, NOTE, CREATED_AT, UPDATED_AT
FROM ATTENDANCE_RECORDS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
  AND WORK_DATE = #{workDate}

SELECT ID, WORKPLACE_ID, USER_ID, WORK_DATE, CHECK_IN_AT, CHECK_OUT_AT, STATUS,
       WORKED_MINUTES, BASE_WAGE, FINAL_WAGE, NOTE, CREATED_AT, UPDATED_AT
FROM ATTENDANCE_RECORDS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
  AND WORK_DATE BETWEEN #{fromDate} AND #{toDate}
ORDER BY WORK_DATE DESC

SELECT COUNT(*)
FROM ATTENDANCE_RECORDS
WHERE WORKPLACE_ID = #{workplaceId}
  AND WORK_DATE = #{today}
  AND CHECK_IN_AT IS NOT NULL

SELECT COUNT(*)
FROM ATTENDANCE_RECORDS
WHERE WORKPLACE_ID = #{workplaceId}
  AND WORK_DATE = #{today}
  AND CHECK_IN_AT IS NOT NULL
  AND CHECK_OUT_AT IS NULL

SELECT ID, WORKPLACE_ID, USER_ID, WORK_DATE, CHECK_IN_AT, CHECK_OUT_AT, STATUS,
       WORKED_MINUTES, BASE_WAGE, FINAL_WAGE, NOTE, CREATED_AT, UPDATED_AT
FROM ATTENDANCE_RECORDS
WHERE WORKPLACE_ID = #{workplaceId}
  AND WORK_DATE BETWEEN #{fromDate} AND #{toDate}

  AND USER_ID = #{userId}

ORDER BY WORK_DATE DESC, USER_ID ASC

SELECT COALESCE(SUM(WORKED_MINUTES), 0) AS totalWorkedMinutes,
       COALESCE(SUM(FINAL_WAGE), 0) AS totalExpectedWage
FROM ATTENDANCE_RECORDS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
